    name="list_all_users",
    description="List all users with pagination support",
    inputSchema={
        "type": "object",
        "properties": {
            "page": {
                "type": "number",
                "description": "Page number (default: 1)",
                "default": 1
            },
            "per_page": {
                "type": "number",
                "description": "Number of users per page (default: 10)",
                "default": 10
            }
        }
    }
)
</code></pre>

Click here for the solution  Add this to your `register_tool_handlers()` method in the `call_tool` function:      ```python     elif name == "list_all_users":         import math          # Get pagination parameters         page = int(arguments.get("page", 1))         per_page = int(arguments.get("per_page", 10))          # Validate parameters         if page &lt; 1:             page = 1         if per_page &lt; 1:             per_page = 10         if per_page &gt; 100:  # Max limit             per_page = 100          # Calculate pagination         total_users = len(users)         total_pages = math.ceil(total_users / per_page) if total_users &gt; 0 else 1          # Ensure page doesn't exceed total pages         if page &gt; total_pages:             page = total_pages          # Calculate slice indices         start_idx = (page - 1) * per_page         end_idx = start_idx + per_page          # Get paginated users         paginated_users = users[start_idx:end_idx]          # Format output         user_list = []         for user in paginated_users:             full_name = user.get('full_name', 'Unknown')             age = user.get('age', 'N/A')             city = user.get('city', 'Unknown')             user_list.append(f"User {user.get('id')}: {full_name}, Age: {age}, City: {city}")          # Build result with metadata         metadata = f"Page {page} of {total_pages} | Total Users: {total_users} | Showing: {len(paginated_users)}"         result = f"{metadata}

